	"wms_include_items" "all"
	"wms_exclude_items" "value_0,red,green,blue"
	"force_imagetype" "jpeg"
  END
  CLASS
	NAME "Índice de Aridez (%)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "0.3 - 0.4"
    EXPRESSION ([pixel] >= 0.3 AND [pixel] < 0.4)
    COLOR 10 160 171
  END
  CLASS
	NAME "0.4 - 0.5"
    EXPRESSION ([pixel] >= 0.4 AND [pixel] < 0.5)
    COLOR 174 224 148
  END
  CLASS
	NAME "0.5 - 0.6"
    EXPRESSION ([pixel] >= 0.5 AND [pixel] < 0.6)
    COLOR 255 119 0
  END
  CLASS
	NAME "0.6 - 0.7"
    EXPRESSION ([pixel] >= 0.6 AND [pixel] < 0.7)
    COLOR 255 191 235
  END
  CLASS
	NAME "0.7 - 0.8"
    EXPRESSION ([pixel] >= 0.7 AND [pixel] < 0.8)
    COLOR 204 255 0
  END
  CLASS
	NAME "0.8 - 0.9"
    EXPRESSION ([pixel] >= 0.8 AND [pixel] < 0.9)
    COLOR 51 255 0
  END
  CLASS
	NAME "0.9 - 1.0"
    EXPRESSION ([pixel] >= 0.9 AND [pixel] < 1.0)
    COLOR 238 255 0
  END
  CLASS
	NAME "1.0 - 1.2"
    EXPRESSION ([pixel] >= 1.0 AND [pixel] < 1.2)
    COLOR 15 187 255
  END
  CLASS
	NAME "1.2 - 1.4"
    EXPRESSION ([pixel] >= 1.2 AND [pixel] < 1.4)
    COLOR 36 87 255
  END
  CLASS
	NAME "1.4 - 1.6"
    EXPRESSION ([pixel] >= 1.4 AND [pixel] < 1.6)
    COLOR 134 0 212
  END
  CLASS
	NAME "1.6 - 1.8"
    EXPRESSION ([pixel] >= 1.6 AND [pixel] <= 2.0)
